arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR_NUMBER = 43
$BRANCH = "copilot/edburns28-python-agent-demo"

# Wait for Copilot cloud agent to finish, then check for action_required workflows
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0

while ($ELAPSED -lt $TIMEOUT) {
    $runs = gh run list -R $REPO --branch "$BRANCH" --json databaseId,name,status,conclusion -L 10 2>&1 | ConvertFrom-Json

    $inProgress = $runs | Where-Object { $_.status -eq "in_progress" -or $_.status -eq "queued" }
    $actionRequired = $runs | Where-Object { $_.status -eq "action_required" }

    Write-Host "[$ELAPSED s] In-progress: $($inProgress.Count), Action-required: $($actionRequired.Count)"
    foreach ($r in $runs) {
        Write-Host "  $($r.name): $($r.status) $($r.conclusion)"
    }

    # If there are action_required runs, break to approve them
    if ($actionRequired.Count -gt 0) {
        Write-Host "Found action_required runs - ready to approve"
        break
    }

    # If Copilot agent is done and there are no action_required, check if CI checks appeared
    $copilotAgent = $runs | Where-Object { $_.name -eq "Running Copilot cloud agent" -and $_.status -eq "in_progress" }
    if (-not $copilotAgent -and $inProgress.Count -eq 0) {
        Write-Host "All runs completed, no action_required found"
        break
    }

    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

# Final status
Write-Host "`n--- Final run status ---"
gh run list -R $REPO --branch "$BRANCH" --json databaseId,name,status,conclusion -L 10 2>&1

